example_bad:
struct Money {
    amount: f64,
}

fn main() {
    let a = Money { amount: 10.0 };
    let b = Money { amount: 20.0 };
    let total = a + b; // Error: cannot add `Money` to `Money`
}

fixes.code:
use std::ops::Add;

impl Add for Money {
    type Output = Money;
    fn add(self, other: Money) -> Money {
        Money { amount: self.amount + other.amount }
    }
}
